class Solution {
public:
    bool backspaceCompare(string s, string t) {
        return buildString(s) == buildString(t);
    }

    string buildString(string s) {
        string result;
        for (char c : s) {
            if (c != '#') {
                result += c;
            } else if (!result.empty()) {
                result.pop_back();
            }
        }
        return result;
    }
};
